<script setup lang="ts">
import OiIcon from 'src/components/ui/OiIcon.vue'
import type {
  StoryBibleSummary,
  StoryCharacterSummary,
  StoryEpisodeSummary,
} from 'src/components/session-workspace/types'

// ── Props ────────────────────────────────────────────────────────────────────

withDefaults(defineProps<{
  /** Story bible canon projection; null until the page has computed it. */
  bible?: StoryBibleSummary | null
  /** Series episode index; empty array when no episodes exist yet. */
  episodes?: StoryEpisodeSummary[]
  /** Currently selected episode (highlights the row). */
  selectedEpisodeId?: string | null
}>(), {
  bible: null,
  episodes: () => [],
  selectedEpisodeId: null,
})

const emit = defineEmits<{
  (e: 'episode-select', id: string): void
}>()

// ── Handlers ──────────────────────────────────────────────────────────────────

function onEpisodeSelect(id: string): void {
  emit('episode-select', id)
}

// ── Label helpers ─────────────────────────────────────────────────────────────

function roleLabel(role: StoryCharacterSummary['role']): string {
  // TODO(coder): localize via i18n if a translation layer is introduced.
  switch (role) {
    case 'protagonist': return '主角'
    case 'antagonist': return '反派'
    case 'supporting': return '配角'
    case 'extra': return '群演'
  }
}

function episodeStatusLabel(status: StoryEpisodeSummary['status']): string {
  // TODO(coder): localize via i18n if a translation layer is introduced.
  switch (status) {
    case 'draft': return '草稿'
    case 'storyboard': return '分镜'
    case 'generating': return '生成中'
    case 'review': return '审阅'
    case 'done': return '完成'
  }
}
</script>

